        console.log(a.b + a.c)""".stripMargin.trim,
      options = AllOff.copy(
        hoistProps = true,
        reduceVars = true,
        toplevel = ToplevelConfig()
      )
    )
  }

  // =========================================================================
  // toplevel_var
  // =========================================================================
  test("toplevel_var") {
    assertCompresses(
      input = """var a = {
            b: 1,
            c: 2
        };
        console.log(a.b + a.c)""".stripMargin.trim,
      expected = """var a = {
            b: 1,
            c: 2
        };
        console.log(a.b + a.c)""".stripMargin.trim,
      options = AllOff.copy(
        hoistProps = true,
        reduceVars = true,
        toplevel = ToplevelConfig()
      )
    )
  }

  // =========================================================================
  // undefined_key
  // =========================================================================
  test("undefined_key".fail) {
    assertCompresses(
      input = """var a, o = {};
        o[a] = 1;
        o.b = 2;
        console.log(o[a] + o.b)""".stripMargin.trim,
      expected = "console.log(3)",
      options = AllOff.copy(
        evaluate = true,
        hoistProps = true,
        joinVars = true,
        passes = 4,
        reduceVars = true,
        toplevel = ToplevelConfig(funcs = true, vars = true),
        unused = true
      )
    )
  }

  // =========================================================================
  // issue_3021
  // =========================================================================
  test("issue_3021") {
    assertCompresses(
      input = """var a = 1, b = 2;
        (function() {
            b = a;
            if (a++ + b--)
                return 1;
            return;
            var b = {};
        })();
        console.log(a, b)""".stripMargin.trim,
      expected = """var a = 1, b = 2;
        (function() {
            b = a;
            if (a++ + b--)
                return 1;
            return;
            var b = {};
        })();
        console.log(a, b)""".stripMargin.trim,
      options = AllOff.copy(
        hoistProps = true,
        reduceVars = true
      )
    )
  }

  // =========================================================================
  // issue_3046
  // =========================================================================
  test("issue_3046") {
    assertCompresses(
      input = """console.log(function(a) {
            do {
                var b = {
                    c: a++
                };
            } while (b.c && a);
            return a;
        }(0))""".stripMargin.trim,
      expected = """// NOTE: differs from uglify-js, but produces correct result
        console.log(function(a) {
            do {
                var b = {
                    c: a++
                };
            } while (b.c && a);
            return a;
        }(0))""".stripMargin.trim,
      options = AllOff.copy(
        hoistProps = true,
        reduceVars = true
      )
    )
  }

  // =========================================================================
  // issue_3071_3
  // =========================================================================
  test("issue_3071_3") {
    assertCompresses(
      input = """var c = 0;
        (function(a, b) {
            (function f(o) {
                var n = 2;
                while (--b + (o = {
                    p: c++,
                }) && --n > 0);
            })();
        })();
        console.log(c)""".stripMargin.trim,
      expected = """var c = 0;
        (function(a, b) {
            (function f(o) {
                var n = 2;
                while (--b + (o = {
                    p: c++,
                }) && --n > 0);
            })();
        })();
        console.log(c)""".stripMargin.trim,
      options = AllOff.copy(
        hoistProps = true,
        reduceVars = true
      )
    )
  }

